export interface JettChatUser {
  id: string; // wallet pubkey (primary key)
  x_handle?: string;
  x_id?: string;
  wallets: string[];
  message_count: number;
  is_agent: boolean;
  display_name?: string;
  avatar_url?: string;
  created: number;
}

export type IdentityType = "wallet" | "x_handle" | "agent";

export function resolveIdentityType(id: string): IdentityType {
  if (id.startsWith("agent:")) return "agent";
  if (id.startsWith("@") || /^[a-zA-Z0-9_]{1,15}$/.test(id)) return "x_handle";
  return "wallet";
}

export function displayName(user: JettChatUser): string {
  if (user.display_name) return user.display_name;
  if (user.x_handle) return `@${user.x_handle}`;
  if (user.is_agent) return `Agent:${user.id.slice(0, 8)}`;
  return `${user.id.slice(0, 4)}...${user.id.slice(-4)}`;
}
