export interface JettChatChannel {
  id: string;
  name: string;
  type: "global" | "dm" | "group" | "agent";
  participants: string[]; // wallet pubkeys or x_handles
  created: number;
}

export const GLOBAL_CHANNEL: JettChatChannel = {
  id: "jettchat-global",
  name: "#JettChat",
  type: "global",
  participants: [], // open to all authenticated users
  created: 0,
};

export function createDMChannel(
  participantA: string,
  participantB: string
): JettChatChannel {
  const sorted = [participantA, participantB].sort();
  return {
    id: `dm:${sorted[0]}:${sorted[1]}`,
    name: `DM`,
    type: "dm",
    participants: sorted,
    created: Date.now(),
  };
}
