/**
 * JOE WebSocket client — connects to JOE WS server (port 8765)
 * Based on existing JOEWebSocketService.ts pattern
 */
import { encodeBase64, decodeBase64 } from "tweetnacl-util";
import {
  createSession,
  completeHandshake,
  nextMessageKey,
  type SessionKeys,
} from "../encryption/keys";
import { encryptMessage, decryptMessage, boxDecrypt } from "../encryption/e2e";
import type { KnotParams } from "../encryption/tkdf";
import { generateMessageId, type PlaintextMessage } from "../models/message";

export type ConnectionState = "disconnected" | "connecting" | "connected" | "e2e_ready";

export interface WSClientConfig {
  url: string; // ws://100.85.183.16:8765 or wss://...
  myPubkey: string; // wallet pubkey for identity
  knotParams?: KnotParams;
  reconnectAttempts?: number;
  reconnectBaseDelay?: number;
}

type MessageCallback = (msg: PlaintextMessage) => void;
type StateCallback = (state: ConnectionState) => void;

export class JettChatWSClient {
  private ws: WebSocket | null = null;
  private session: SessionKeys;
  private config: WSClientConfig;
  private state: ConnectionState = "disconnected";
  private messageCallbacks = new Set<MessageCallback>();
  private stateCallbacks = new Set<StateCallback>();
  private reconnectCount = 0;

  constructor(config: WSClientConfig) {
    this.config = config;
    this.session = createSession();
  }

  connect(): void {
    if (this.ws) return;
    this.setState("connecting");

    this.ws = new WebSocket(this.config.url);

    this.ws.onopen = () => {
      this.setState("connected");
      this.reconnectCount = 0;
      this.initiateHandshake();
    };

    this.ws.onmessage = (event) => {
      this.handleMessage(event.data);
    };

    this.ws.onclose = () => {
      this.ws = null;
      this.setState("disconnected");
      this.maybeReconnect();
    };

    this.ws.onerror = () => {
      this.ws?.close();
    };
  }

  disconnect(): void {
    this.reconnectCount = Infinity; // prevent reconnect
    this.ws?.close();
    this.ws = null;
    this.setState("disconnected");
  }

  send(to: string, text: string, isPublic = false): void {
    if (!this.session.rootKey || !this.ws) {
      throw new Error("Not connected or E2E not ready");
    }

    const { key, session } = nextMessageKey(this.session);
    this.session = session;

    const encrypted = encryptMessage(text, key);

    const msg = {
      type: "message",
      id: generateMessageId(),
      from: this.config.myPubkey,
      to,
      ciphertext: encrypted.ciphertext,
      nonce: encrypted.nonce,
      timestamp: Date.now(),
      public: isPublic,
      msg_type: "text",
      counter: this.session.messageCounter - 1,
    };

    this.ws.send(JSON.stringify(msg));
  }

  onMessage(cb: MessageCallback): () => void {
    this.messageCallbacks.add(cb);
    return () => this.messageCallbacks.delete(cb);
  }

  onStateChange(cb: StateCallback): () => void {
    this.stateCallbacks.add(cb);
    return () => this.stateCallbacks.delete(cb);
  }

  getState(): ConnectionState {
    return this.state;
  }

  private setState(state: ConnectionState): void {
    this.state = state;
    this.stateCallbacks.forEach((cb) => cb(state));
  }

  private initiateHandshake(): void {
    const pubKeyB64 = encodeBase64(this.session.keyPair.publicKey);
    this.ws?.send(
      JSON.stringify({ type: "handshake", public_key: pubKeyB64 })
    );
  }

  private handleMessage(data: string): void {
    try {
      const parsed = JSON.parse(data);

      if (parsed.type === "handshake_response") {
        const serverPubKey = decodeBase64(parsed.public_key);
        const encryptedSessionKey = decodeBase64(parsed.session_key);

        // Decrypt session key using box
        const sessionKey = boxDecrypt(
          encryptedSessionKey,
          serverPubKey,
          this.session.keyPair.secretKey
        );

        // Complete TKDF handshake
        this.session = completeHandshake(
          this.session,
          serverPubKey,
          this.config.myPubkey,
          parsed.server_id ?? "server",
          this.config.knotParams
        );

        this.setState("e2e_ready");
        return;
      }

      if (parsed.type === "message" && this.session.rootKey) {
        const { key } = nextMessageKey({
          ...this.session,
          messageCounter: parsed.counter ?? 0,
        });

        const text = decryptMessage(
          { ciphertext: parsed.ciphertext, nonce: parsed.nonce },
          key
        );

        const msg: PlaintextMessage = {
          id: parsed.id,
          from: parsed.from,
          to: parsed.to,
          text,
          timestamp: parsed.timestamp,
          public: parsed.public ?? false,
          type: parsed.msg_type ?? "text",
        };

        this.messageCallbacks.forEach((cb) => cb(msg));
      }
    } catch {
      // Ignore malformed messages
    }
  }

  private maybeReconnect(): void {
    const maxAttempts = this.config.reconnectAttempts ?? 5;
    const baseDelay = this.config.reconnectBaseDelay ?? 1000;

    if (this.reconnectCount >= maxAttempts) return;

    const delay = baseDelay * Math.pow(2, this.reconnectCount);
    this.reconnectCount++;

    setTimeout(() => {
      this.session = createSession(); // Fresh keys on reconnect
      this.connect();
    }, delay);
  }
}
