/**
 * Session key management — orchestrates E2E + TKDF
 */
import { generateKeyPair, deriveSharedSecret, type KeyPair } from "./e2e";
import {
  deriveConversationSeed,
  deriveRootKey,
  deriveMessageKey,
  type KnotParams,
  type TKDFResult,
} from "./tkdf";

export interface SessionKeys {
  keyPair: KeyPair;
  sharedSecret: Uint8Array | null;
  rootKey: Uint8Array | null;
  messageCounter: number;
  tkdfEnabled: boolean;
}

export function createSession(): SessionKeys {
  return {
    keyPair: generateKeyPair(),
    sharedSecret: null,
    rootKey: null,
    messageCounter: 0,
    tkdfEnabled: false,
  };
}

export function completeHandshake(
  session: SessionKeys,
  theirPublicKey: Uint8Array,
  myPubkeyBase58: string,
  theirPubkeyBase58: string,
  knotParams?: KnotParams
): SessionKeys {
  const sharedSecret = deriveSharedSecret(session.keyPair.secretKey, theirPublicKey);
  const conversationSeed = deriveConversationSeed(myPubkeyBase58, theirPubkeyBase58);
  const result = deriveRootKey(sharedSecret, conversationSeed, knotParams);

  return {
    ...session,
    sharedSecret,
    rootKey: result.rootKey,
    messageCounter: 0,
    tkdfEnabled: result.knotParamsUsed,
  };
}

export function nextMessageKey(session: SessionKeys): {
  key: Uint8Array;
  session: SessionKeys;
} {
  if (!session.rootKey) {
    throw new Error("Session handshake not complete");
  }

  const key = deriveMessageKey(session.rootKey, session.messageCounter);
  return {
    key,
    session: { ...session, messageCounter: session.messageCounter + 1 },
  };
}
