/**
 * Matrix/Conduit bridge — relays messages to/from the OPTX Matrix homeserver
 * Conduit server: matrix.jettoptics.ai (Jetson :6167)
 * Room: #optx:jettoptics.ai
 */

export interface MatrixConfig {
  homeserverUrl: string; // https://matrix.jettoptics.ai
  accessToken: string;
  roomId: string;
}

export interface MatrixMessage {
  event_id: string;
  sender: string;
  body: string;
  timestamp: number;
}

type MatrixCallback = (msg: MatrixMessage) => void;

export class MatrixBridge {
  private config: MatrixConfig;
  private callbacks = new Set<MatrixCallback>();
  private syncToken: string | null = null;
  private polling = false;

  constructor(config: MatrixConfig) {
    this.config = config;
  }

  async sendMessage(body: string): Promise<string> {
    const txnId = `jettchat-${Date.now()}-${Math.random().toString(36).slice(2)}`;
    const url = `${this.config.homeserverUrl}/_matrix/client/v3/rooms/${encodeURIComponent(this.config.roomId)}/send/m.room.message/${txnId}`;

    const res = await fetch(url, {
      method: "PUT",
      headers: {
        Authorization: `Bearer ${this.config.accessToken}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        msgtype: "m.text",
        body,
      }),
    });

    if (!res.ok) throw new Error(`Matrix send failed: ${res.status}`);
    const data = await res.json();
    return data.event_id;
  }

  startPolling(): void {
    if (this.polling) return;
    this.polling = true;
    this.poll();
  }

  stopPolling(): void {
    this.polling = false;
  }

  onMessage(cb: MatrixCallback): () => void {
    this.callbacks.add(cb);
    return () => this.callbacks.delete(cb);
  }

  private async poll(): Promise<void> {
    while (this.polling) {
      try {
        const params = new URLSearchParams({
          timeout: "30000",
          filter: JSON.stringify({
            room: {
              rooms: [this.config.roomId],
              timeline: { limit: 20 },
            },
          }),
        });

        if (this.syncToken) params.set("since", this.syncToken);

        const url = `${this.config.homeserverUrl}/_matrix/client/v3/sync?${params}`;
        const res = await fetch(url, {
          headers: { Authorization: `Bearer ${this.config.accessToken}` },
        });

        if (!res.ok) {
          await new Promise((r) => setTimeout(r, 5000));
          continue;
        }

        const data = await res.json();
        this.syncToken = data.next_batch;

        const roomData = data.rooms?.join?.[this.config.roomId];
        const events = roomData?.timeline?.events ?? [];

        for (const event of events) {
          if (event.type === "m.room.message") {
            const msg: MatrixMessage = {
              event_id: event.event_id,
              sender: event.sender,
              body: event.content?.body ?? "",
              timestamp: event.origin_server_ts,
            };
            this.callbacks.forEach((cb) => cb(msg));
          }
        }
      } catch {
        await new Promise((r) => setTimeout(r, 5000));
      }
    }
  }
}
