/**
 * E2E Encryption — X25519 key exchange + NaCl SecretBox
 * Based on existing JOEWebSocketService.ts pattern
 */
import nacl from "tweetnacl";
import { encodeBase64, decodeBase64 } from "tweetnacl-util";

export interface KeyPair {
  publicKey: Uint8Array;
  secretKey: Uint8Array;
}

export interface EncryptedPayload {
  ciphertext: string; // Base64
  nonce: string; // Base64
}

export function generateKeyPair(): KeyPair {
  return nacl.box.keyPair();
}

export function deriveSharedSecret(
  mySecretKey: Uint8Array,
  theirPublicKey: Uint8Array
): Uint8Array {
  return nacl.box.before(theirPublicKey, mySecretKey);
}

export function encryptMessage(
  plaintext: string,
  sessionKey: Uint8Array
): EncryptedPayload {
  const nonce = nacl.randomBytes(nacl.secretbox.nonceLength);
  const messageBytes = new TextEncoder().encode(plaintext);
  const ciphertext = nacl.secretbox(messageBytes, nonce, sessionKey);

  if (!ciphertext) throw new Error("Encryption failed");

  return {
    ciphertext: encodeBase64(ciphertext),
    nonce: encodeBase64(nonce),
  };
}

export function decryptMessage(
  payload: EncryptedPayload,
  sessionKey: Uint8Array
): string {
  const ciphertext = decodeBase64(payload.ciphertext);
  const nonce = decodeBase64(payload.nonce);
  const plaintext = nacl.secretbox.open(ciphertext, nonce, sessionKey);

  if (!plaintext) throw new Error("Decryption failed — invalid key or tampered ciphertext");

  return new TextDecoder().decode(plaintext);
}

/**
 * Encrypt with asymmetric box (for handshake / key exchange)
 */
export function boxEncrypt(
  plaintext: Uint8Array,
  theirPublicKey: Uint8Array,
  mySecretKey: Uint8Array
): Uint8Array {
  const nonce = nacl.randomBytes(nacl.box.nonceLength);
  const ciphertext = nacl.box(plaintext, nonce, theirPublicKey, mySecretKey);
  if (!ciphertext) throw new Error("Box encryption failed");

  // Prepend nonce to ciphertext (standard tweetnacl convention)
  const combined = new Uint8Array(nonce.length + ciphertext.length);
  combined.set(nonce);
  combined.set(ciphertext, nonce.length);
  return combined;
}

/**
 * Decrypt asymmetric box (nonce prepended to ciphertext)
 */
export function boxDecrypt(
  combined: Uint8Array,
  theirPublicKey: Uint8Array,
  mySecretKey: Uint8Array
): Uint8Array {
  const nonce = combined.slice(0, nacl.box.nonceLength);
  const ciphertext = combined.slice(nacl.box.nonceLength);
  const plaintext = nacl.box.open(ciphertext, nonce, theirPublicKey, mySecretKey);

  if (!plaintext) throw new Error("Box decryption failed");
  return plaintext;
}
