/**
 * TKDF — Topological Key Derivation Function
 *
 * Augments X25519 shared secret with knot polynomial invariants
 * for post-quantum hybrid encryption.
 *
 * Key derivation:
 *   SHAKE-256("OPTX-TKDF-v1.0\x00" ∥ α_K ∥ ν_K ∥ ω_K ∥ seed ∥ shared_secret)
 *
 * Per-conversation deterministic: seed = SHAKE-256(sort(pubkey_A, pubkey_B))
 * Per-message ratcheting: HKDF(root_key, message_counter)
 */
import { shake256 } from "js-sha3";

const DOMAIN_SEPARATOR = "OPTX-TKDF-v1.0\x00";

export interface KnotParams {
  alexanderEval: Float64Array; // α_K: complex128 (2 floats: real, imag)
  jonesEval: Float64Array; // ν_K: complex128 (2 floats: real, imag)
  writhe: number; // ω_K: signed integer
}

export interface TKDFResult {
  rootKey: Uint8Array; // 32 bytes — use as NaCl SecretBox key
  knotParamsUsed: boolean;
}

/**
 * Derive conversation seed from sorted participant pubkeys.
 * Same two users always produce the same seed.
 */
export function deriveConversationSeed(
  pubkeyA: string,
  pubkeyB: string
): Uint8Array {
  const sorted = [pubkeyA, pubkeyB].sort();
  const input = new TextEncoder().encode(sorted.join(":"));
  const hash = shake256.create(256);
  hash.update(Array.from(input));
  return new Uint8Array(hash.arrayBuffer());
}

/**
 * Derive hybrid root key using TKDF.
 * Falls back to plain shared_secret if knot params unavailable.
 */
export function deriveRootKey(
  sharedSecret: Uint8Array,
  conversationSeed: Uint8Array,
  knotParams?: KnotParams
): TKDFResult {
  if (!knotParams) {
    // Fallback: plain X25519 key (no knot augmentation)
    const hash = shake256.create(256);
    hash.update(Array.from(sharedSecret));
    hash.update(Array.from(conversationSeed));
    return {
      rootKey: new Uint8Array(hash.arrayBuffer()),
      knotParamsUsed: false,
    };
  }

  // Full TKDF: domain_separator ∥ α_K ∥ ν_K ∥ ω_K ∥ seed ∥ shared_secret
  const hash = shake256.create(256);

  // Domain separator
  hash.update(Array.from(new TextEncoder().encode(DOMAIN_SEPARATOR)));

  // Alexander polynomial evaluation (16 bytes: 2x float64)
  hash.update(Array.from(new Uint8Array(knotParams.alexanderEval.buffer)));

  // Jones polynomial evaluation (16 bytes: 2x float64)
  hash.update(Array.from(new Uint8Array(knotParams.jonesEval.buffer)));

  // Writhe (4 bytes: int32 big-endian)
  const writheBuf = new ArrayBuffer(4);
  new DataView(writheBuf).setInt32(0, knotParams.writhe, false);
  hash.update(Array.from(new Uint8Array(writheBuf)));

  // Conversation seed
  hash.update(Array.from(conversationSeed));

  // X25519 shared secret
  hash.update(Array.from(sharedSecret));

  return {
    rootKey: new Uint8Array(hash.arrayBuffer()),
    knotParamsUsed: true,
  };
}

/**
 * Per-message ratchet: derive message key from root key + counter.
 * Provides forward secrecy — compromise of one message key doesn't
 * reveal keys for other messages.
 */
export function deriveMessageKey(
  rootKey: Uint8Array,
  messageCounter: number
): Uint8Array {
  const hash = shake256.create(256);
  hash.update(Array.from(rootKey));

  const counterBuf = new ArrayBuffer(8);
  new DataView(counterBuf).setBigUint64(0, BigInt(messageCounter), false);
  hash.update(Array.from(new Uint8Array(counterBuf)));

  return new Uint8Array(hash.arrayBuffer());
}

/**
 * Default knot params for trefoil knot (3₁) — the simplest non-trivial knot.
 * Used as the default TKDF knot when no custom knot is specified.
 */
export function trefoilKnotParams(): KnotParams {
  // Alexander polynomial of trefoil at e^{2πi/3}: α(t) = t - 1 + t^{-1}
  // Evaluated at t = e^{2πi/3} ≈ -0.5 + 0.866i
  // α = (-0.5 + 0.866i) - 1 + (-0.5 - 0.866i) = -2
  const alexander = new Float64Array(2);
  alexander[0] = -2.0; // real
  alexander[1] = 0.0; // imag

  // Jones polynomial of trefoil at e^{2πi/3}:
  // V(t) = -t^{-4} + t^{-3} + t^{-1}
  const jones = new Float64Array(2);
  jones[0] = -1.0; // real (approximate)
  jones[1] = 1.732; // imag (approximate)

  return {
    alexanderEval: alexander,
    jonesEval: jones,
    writhe: 3,
  };
}
