export interface JettChatMessage {
  id: string;
  from: string; // sender wallet pubkey or x_handle
  to: string; // recipient pubkey, x_handle, or channel ID
  content: Uint8Array; // encrypted payload
  nonce: Uint8Array; // NaCl nonce
  timestamp: number; // Unix ms
  public: boolean; // true = readable by any authenticated user
  type: "text" | "system" | "x_activity" | "agent";
}

export interface PlaintextMessage {
  id: string;
  from: string;
  to: string;
  text: string;
  timestamp: number;
  public: boolean;
  type: JettChatMessage["type"];
}

export function generateMessageId(): string {
  const ts = Date.now().toString(36);
  const rand = Math.random().toString(36).slice(2, 10);
  return `${ts}-${rand}`;
}
