/**
 * X Activity API SSE consumer
 * Connects to /api/x/stream (our SSE proxy) to receive real-time X events
 */

export interface XActivityEvent {
  event_type: string;
  data: Record<string, unknown>;
  timestamp: string;
}

export type ActivityCallback = (event: XActivityEvent) => void;

export class XActivityStream {
  private eventSource: EventSource | null = null;
  private callbacks = new Set<ActivityCallback>();
  private url: string;

  constructor(streamUrl = "/api/x/stream") {
    this.url = streamUrl;
  }

  connect(): void {
    if (this.eventSource) return;

    this.eventSource = new EventSource(this.url);

    this.eventSource.onmessage = (event) => {
      try {
        const parsed: XActivityEvent = JSON.parse(event.data);
        this.callbacks.forEach((cb) => cb(parsed));
      } catch {
        // Ignore malformed events
      }
    };

    this.eventSource.onerror = () => {
      // EventSource auto-reconnects
    };
  }

  disconnect(): void {
    this.eventSource?.close();
    this.eventSource = null;
  }

  onEvent(cb: ActivityCallback): () => void {
    this.callbacks.add(cb);
    return () => this.callbacks.delete(cb);
  }

  isConnected(): boolean {
    return this.eventSource?.readyState === EventSource.OPEN;
  }
}
